const now = new Date();
let shouldRun = true;

try {
  const binary = $input.first().binary;
  if (binary) {
    for (const key of Object.keys(binary)) {
      const buf = await this.helpers.getBinaryDataBuffer(0, key);
      const content = buf.toString('utf-8');
      const dateMatch = content.match(/^## (\d{4}-\d{2}-\d{2})/m);
      if (dateMatch) {
        const lastRunDate = new Date(dateMatch[1] + 'T12:00:00');
        const hoursSince = (now - lastRunDate) / (1000 * 60 * 60);
        if (hoursSince < 20) {
          shouldRun = false;
        }
      }
    }
  }
} catch (e) {
  shouldRun = true;
}

return [{ json: { shouldRun, timestamp: now.toISOString() } }];

const results = $input.first().json.results || [];

return results.map(job => ({
  json: {
    id: job.id.toString(),
    source: "Adzuna",
    title: job.title,
    company: job.company.display_name,
    location: job.location.display_name,
    url: job.redirect_url,
    date_posted: job.created.split('T')[0],
    description: job.description,
    salary_min: job.salary_min || null,
    salary_max: job.salary_max || null,
    salary_currency: job.salary_min ? "GBP" : null
  }
}));

// Get listings from Normalize Listings node
const listings = $('Normalize Listings').all().map(item => item.json);

// Get context files - try different binary access patterns
const targetRolesItem = $('Read Target Roles').first();
const profileItem = $('Read Profile').first();

let targetRoles = '';
let profile = '';

// Extract text content from binary data
try {
  const trBinary = targetRolesItem.binary;
  for (const key of Object.keys(trBinary)) {
    const buf = await this.helpers.getBinaryDataBuffer(0, key, 0);
    targetRoles = buf.toString('utf-8');
  }
} catch (e) {
  targetRoles = 'ERROR: Could not read target-roles.md: ' + e.message;
}

try {
  const prBinary = profileItem.binary;
  for (const key of Object.keys(prBinary)) {
    const buf = await this.helpers.getBinaryDataBuffer(0, key, 0);
    profile = buf.toString('utf-8');
  }
} catch (e) {
  profile = 'ERROR: Could not read profile.md: ' + e.message;
}

// Build the listings text
const listingsText = listings.map((job, i) => 
  `### Listing ${i + 1}\n` +
  `Title: ${job.title}\n` +
  `Company: ${job.company}\n` +
  `Location: ${job.location}\n` +
  `URL: ${job.url}\n` +
  `Source: ${job.source}\n` +
  `Posted: ${job.date_posted}\n` +
  `Salary: ${job.salary_min && job.salary_max ? job.salary_min + '-' + job.salary_max + ' ' + (job.salary_currency || '') : 'Not stated'}\n` +
  `\nJob Description:\n${job.description}\n`
).join('\n---\n\n');

const totalListings = listings.length;

const scoringPrompt = `You are a Job Scout for a product management job search system. Your job is to evaluate job listings against the user's target criteria and professional profile, then produce a structured scout report section.

## TARGET CRITERIA

${targetRoles}

## PROFESSIONAL PROFILE

${profile}

## RAW LISTINGS (${totalListings} total)

${listingsText}

## YOUR TASK

For each listing, assess TWO dimensions independently:

TARGET ALIGNMENT — how well does this match the user's stated preferences in target criteria? Consider industry, role type, company size, location, culture signals, and deal-breakers.

PROFILE FIT — how credible is the user as a candidate based on their professional profile? Consider relevant experience, skills match, seniority alignment, and transferable strengths.

Use these to assign tiers:

**Strong Match** — High on both dimensions. What the user wants AND is well-qualified for.

**Worth a Look — Aspirational** — Matches target criteria but the user's profile is a stretch. Flag specifically what experience or skills are missing and why it might still be worth pursuing.

**Worth a Look — Experience Fit** — User's profile is strong for this role but it falls outside stated target criteria. Explain why the user's experience is relevant and what makes this interesting despite not being in their target scope.

**Skip** — Low on both dimensions, OR hits a deal-breaker.

## RULES

- Be honest. A listing that requires 10 years of domain experience the user doesn't have is not a Strong Match, even if everything else aligns. It may be Aspirational — say so clearly.
- Do not inflate tiers to seem helpful. Fewer Strong Matches with high accuracy is better than many Strong Matches that waste the user's time.
- When a JD is ambiguous (vague requirements, unclear seniority), say so in the flags rather than guessing optimistically.
- Deal-breakers from target criteria are absolute. If the user says "no adtech," a perfect-looking adtech role is a Skip regardless of profile fit.
- Look beyond job titles. A "Product Owner" JD that reads like a Senior PM role should be scored on its actual content. A "Director of Product" that's really a solo PM at a 5-person startup should be flagged.
- Experience Fit listings are valuable. If the user's profile is a strong match for a role outside their target industries, surface it.
- Transferable skills matter. Platform migration, team scaling, B2B SaaS growth — these apply across industries. Score profile fit based on what's transferable, not just on industry keyword matches.

## OUTPUT FORMAT

Start with a metadata line:
> Sources: Adzuna | Found: ${totalListings} | Strong: [count] | Aspirational: [count] | Experience Fit: [count] | Skipped: [count]

Then for each listing that is Strong Match or Worth a Look (either type), produce:

**[Company] — [Job Title]**
Source: [source] | [Location] | Posted: [date]
URL: [url]
Match: [2-3 sentences explaining the match]
Flags: [Any concerns or ambiguities. Omit this line if there are no flags.]

For skipped listings, produce only a summary count grouped by skip reason. Do not list individual skipped listings.

Produce ONLY the report content. No preamble, no commentary, no markdown code fences.`;

return [{
  json: {
    scoringPrompt,
    totalListings,
    timestamp: new Date().toISOString().split('T')[0]
  }
}];

const prompt = $input.first().json.scoringPrompt;
const timestamp = $input.first().json.timestamp;
const totalListings = $input.first().json.totalListings;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': 'YOUR_ANTHROPIC_API_KEY',
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json'
  },
  body: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 4096,
    messages: [
      { role: 'user', content: prompt }
    ]
  },
  json: true
});

const reportContent = response.content[0].text;

return [{
  json: {
    reportContent,
    timestamp,
    totalListings
  }
}];

const reportContent = $input.first().json.reportContent;
const timestamp = $input.first().json.timestamp;

const newSection = `## ${timestamp}\n\n${reportContent}\n\n---\n`;

// Try to get existing report from the node we read at workflow start
let existingContent = '';
try {
  const readNode = $('Read Scout Report').first();
  if (readNode.binary) {
    for (const key of Object.keys(readNode.binary)) {
      const buf = await this.helpers.getBinaryDataBuffer(0, key, 0);
      existingContent = buf.toString('utf-8');
    }
  }
} catch (e) {
  existingContent = '';
}

let finalContent;
if (existingContent && existingContent.startsWith('# Job Scout Report')) {
  const titleEnd = existingContent.indexOf('\n') + 1;
  const title = existingContent.substring(0, titleEnd);
  const rest = existingContent.substring(titleEnd);
  finalContent = title + '\n' + newSection + '\n' + rest;
} else {
  finalContent = '# Job Scout Report\n\n' + newSection;
}

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(finalContent, 'utf-8'),
  'scout-report.md',
  'text/markdown'
);

return [{
  json: { success: true, timestamp },
  binary: { data: binaryData }
}];
